"""
Drive the Deep Dyna-Q dialog system on the CamRest676 restaurant dataset.

Differences vs. the original run.py:

* Loads restaurant data files generated by
  deep_dialog/data/camrest676/build_camrest_data.py
* Skips the pretrained LSTM NLG and NLU models -- the rewrite uses the
  template-only fallback in nlg.py and runs at dia-act level (NLU is a
  no-op) so no movie-domain models are needed.
* Defaults to --agt 5 (RequestBasicsAgent) for an easy smoke test against
  the rule-based user simulator. Pass --agt 9 to train AgentDQN.
"""

import argparse
import copy
import json
import os
import pickle
import random
from datetime import datetime
import numpy
import numpy as np
import torch

try:
    from torch.utils.tensorboard import SummaryWriter
except ImportError:  # optional: pip install tensorboard
    SummaryWriter = None

os.chdir(os.path.dirname(os.path.abspath(__file__)) or './')

from deep_dialog import dialog_config
from deep_dialog.agents import (
    AgentCmd,
    AgentDQN,
    AgentReact,
    AgentMuZero,
    EchoAgent,
    InformAgent,
    RandomAgent,
    RequestAllAgent,
    RequestBasicsAgent,
)
from deep_dialog.dialog_system import DialogManager, text_to_dict
from deep_dialog.nlg import nlg
from deep_dialog.nlu import nlu
from deep_dialog.usersims import ModelBasedSimulator, RuleSimulator, UserSimulator


def load_pickle(path):
    with open(path, 'rb') as f:
        return pickle.load(f, encoding='latin1')


def main():
    parser = argparse.ArgumentParser()

    data_dir = './deep_dialog/data/camrest676'
    parser.add_argument('--dict_path',      default=os.path.join(data_dir, 'camrest_dict.p'))
    parser.add_argument('--kb_path',        default=os.path.join(data_dir, 'camrest_kb.p'))
    parser.add_argument('--act_set',        default=os.path.join(data_dir, 'dia_acts_camrest.txt'))
    parser.add_argument('--slot_set',       default=os.path.join(data_dir, 'slot_set_camrest.txt'))
    parser.add_argument('--goal_file_path', default=os.path.join(data_dir, 'camrest_user_goals.p'))
    parser.add_argument('--diaact_nl_pairs', default=os.path.join(data_dir, 'dia_act_nl_pairs_camrest.json'))

    parser.add_argument('--max_turn', type=int, default=20)
    parser.add_argument('--episodes', type=int, default=50)
    parser.add_argument('--slot_err_prob', type=float, default=0.0)
    parser.add_argument('--slot_err_mode', type=int, default=0)
    parser.add_argument('--intent_err_prob', type=float, default=0.0)

    parser.add_argument('--agt', type=int, default=5,
                        help='0 cmd, 1 inform, 2 request-all, 3 random, 4 echo, 5 request-basics, 9 DQN, 10 React, 11 MuZero')
    parser.add_argument('--usr', type=int, default=1,
                        help='0 real, 1 rule-based simulator')
    parser.add_argument('--epsilon', type=float, default=0.1)

    parser.add_argument('--act_level', type=int, default=0,
                        help='0 dia-act level (no NLU), 1 NL level')
    parser.add_argument('--run_mode', type=int, default=1,
                        help='0 NL only, 1 dia-act only, 2 both')
    parser.add_argument('--auto_suggest', type=int, default=0)
    parser.add_argument('--cmd_input_mode', type=int, default=0)

    # RL agent parameters
    parser.add_argument('--experience_replay_pool_size', type=int, default=10000)
    parser.add_argument('--dqn_hidden_size', type=int, default=256)
    parser.add_argument('--batch_size', type=int, default=64)
    parser.add_argument('--gamma', type=float, default=0.99)
    parser.add_argument('--predict_mode', type=bool, default=False)
    parser.add_argument('--simulation_epoch_size', type=int, default=50)
    parser.add_argument('--warm_start', type=int, default=1)
    parser.add_argument('--warm_start_epochs', type=int, default=100)
    parser.add_argument('--planning_steps', type=int, default=10)
    parser.add_argument('--world_model_weight', type=float, default=0.5,
                        help='Fraction of each DQN training batch drawn from world-model experience')
    parser.add_argument('--per_alpha', type=float, default=0.6,
                        help='PER priority exponent (0=uniform, 1=full PER)')
    parser.add_argument('--per_beta', type=float, default=0.4,
                        help='PER importance-sampling initial beta (anneals to 1.0)')
    parser.add_argument('--trained_model_path', type=str, default=None)
    parser.add_argument('-o', '--write_model_dir', type=str, default='./deep_dialog/checkpoints/')
    parser.add_argument('--save_check_point', type=int, default=10)
    parser.add_argument('--tensorboard', type=int, default=0,
                        help='1 to log scalars to TensorBoard (pip install tensorboard)')
    parser.add_argument('--tensorboard_dir', type=str, default='',
                        help='TensorBoard root log dir; default <write_model_dir>/tensorboard')
    parser.add_argument('--success_rate_threshold', type=float, default=0.6)
    parser.add_argument('--split_fold', type=int, default=5)
    parser.add_argument('--learning_phase', type=str, default='all')
    parser.add_argument('--grounded', type=int, default=0)
    parser.add_argument('--boosted', type=int, default=1)
    parser.add_argument('--train_world_model', type=int, default=1)
    parser.add_argument('--seed', type=int, default=5)
    parser.add_argument('--torch_seed', type=int, default=100)
    parser.add_argument(
        '--sample_dialog_seed',
        type=int,
        default=424242,
        help='DQN only: RNG seed for the sample before/after dialogue. '
             'Use a non-negative integer for a fixed scenario, or -1 to draw a random seed once per run.',
    )
    parser.add_argument(
        '--eval_baseline_episodes',
        type=int,
        default=50,
        help='DQN only: number of eval dialogs for before/after RL metrics (metrics_ab).',
    )

    # Optional: only set these if you want to reuse the pretrained movie LSTM
    # models. Leave empty for the template-only fallback (the default).
    parser.add_argument('--nlg_model_path', type=str, default='')
    parser.add_argument('--nlu_model_path', type=str, default='')

    args = parser.parse_args()
    params = vars(args)
    print('Dialog Parameters:')
    print(json.dumps(params, indent=2))

    numpy.random.seed(params['seed'])
    random.seed(params['seed'])
    torch.manual_seed(params['torch_seed'])

    max_turn = params['max_turn']
    num_episodes = params['episodes']

    # ------------------------------------------------------------------
    # Load data
    # ------------------------------------------------------------------
    all_goal_set = load_pickle(params['goal_file_path'])
    kb = load_pickle(params['kb_path'])
    slot_dictionary = load_pickle(params['dict_path'])

    act_set = text_to_dict(params['act_set'])
    slot_set = text_to_dict(params['slot_set'])

    split_fold = params['split_fold']
    goal_set = {'train': [], 'valid': [], 'test': [], 'all': []}
    for i, g in enumerate(all_goal_set):
        (goal_set['test'] if i % split_fold == 1 else goal_set['train']).append(g)
        goal_set['all'].append(g)

    dialog_config.run_mode = params['run_mode']
    dialog_config.auto_suggest = params['auto_suggest']

    # ------------------------------------------------------------------
    # Agents
    # ------------------------------------------------------------------
    agent_params = {
        'max_turn': max_turn,
        'epsilon': params['epsilon'],
        'agent_run_mode': params['run_mode'],
        'agent_act_level': params['act_level'],
        'experience_replay_pool_size': params['experience_replay_pool_size'],
        'dqn_hidden_size': params['dqn_hidden_size'],
        'batch_size': params['batch_size'],
        'gamma': params['gamma'],
        'predict_mode': params['predict_mode'],
        'trained_model_path': params['trained_model_path'],
        'warm_start': params['warm_start'],
        'cmd_input_mode': params['cmd_input_mode'],
        'world_model_weight': params.get('world_model_weight', 0.5),
        'per_alpha': params.get('per_alpha', 0.6),
        'per_beta': params.get('per_beta', 0.4),
    }

    agt = params['agt']
    if agt == 0:
        agent = AgentCmd(kb, act_set, slot_set, agent_params)
    elif agt == 1:
        agent = InformAgent(kb, act_set, slot_set, agent_params)
    elif agt == 2:
        agent = RequestAllAgent(kb, act_set, slot_set, agent_params)
    elif agt == 3:
        agent = RandomAgent(kb, act_set, slot_set, agent_params)
    elif agt == 4:
        agent = EchoAgent(kb, act_set, slot_set, agent_params)
    elif agt == 5:
        agent = RequestBasicsAgent(kb, act_set, slot_set, agent_params)
    elif agt == 9:
        agent = AgentDQN(kb, act_set, slot_set, agent_params)
    elif agt == 10:
        agent = AgentReact(kb, act_set, slot_set, agent_params)
    elif agt == 11:
        agent = AgentMuZero(kb, act_set, slot_set, agent_params)
    else:
        raise ValueError(f"Unknown --agt {agt}")

    # ------------------------------------------------------------------
    # User simulators
    # ------------------------------------------------------------------
    usersim_params = {
        'max_turn': max_turn,
        'slot_err_probability': params['slot_err_prob'],
        'slot_err_mode': params['slot_err_mode'],
        'intent_err_probability': params['intent_err_prob'],
        'simulator_run_mode': params['run_mode'],
        'simulator_act_level': params['act_level'],
        'learning_phase': params['learning_phase'],
        'hidden_size': params['dqn_hidden_size'],
    }

    if params['usr'] == 0:
        user_sim = UserSimulator(slot_dictionary, act_set, slot_set, goal_set, usersim_params)
    elif params['usr'] == 1:
        user_sim = RuleSimulator(slot_dictionary, act_set, slot_set, goal_set, usersim_params)
    else:
        raise ValueError(f"Unknown --usr {params['usr']}")

    world_model = ModelBasedSimulator(slot_dictionary, act_set, slot_set, goal_set, usersim_params)
    agent.set_user_planning(world_model)

    # ------------------------------------------------------------------
    # NLG: template-first, LSTM only if a model path was supplied.
    # ------------------------------------------------------------------
    nlg_model = nlg()
    nlg_model.load_predefine_act_nl_pairs(params['diaact_nl_pairs'])
    if params['nlg_model_path']:
        nlg_model.load_nlg_model(params['nlg_model_path'])

    agent.set_nlg_model(nlg_model)
    user_sim.set_nlg_model(nlg_model)
    world_model.set_nlg_model(nlg_model)

    # ------------------------------------------------------------------
    # NLU: no-op when no model path is supplied.
    # ------------------------------------------------------------------
    nlu_model = nlu()
    if params['nlu_model_path']:
        nlu_model.load_nlu_model(params['nlu_model_path'])

    agent.set_nlu_model(nlu_model)
    user_sim.set_nlu_model(nlu_model)
    world_model.set_nlu_model(nlu_model)

    # ------------------------------------------------------------------
    # Dialog Manager + run loop (mirrors run.py without the movie comments)
    # ------------------------------------------------------------------
    dialog_manager = DialogManager(agent, user_sim, world_model, act_set, slot_set, kb)

    status = {'successes': 0, 'count': 0, 'cumulative_reward': 0}

    batch_size = params['batch_size']
    warm_start = params['warm_start']
    warm_start_epochs = params['warm_start_epochs']
    planning_steps = params['planning_steps']
    agent.planning_steps = planning_steps

    success_rate_threshold = params['success_rate_threshold']
    save_check_point = params['save_check_point']

    best_model = {'model': copy.deepcopy(agent)}
    best_res = {'success_rate': 0, 'ave_reward': float('-inf'),
                'ave_turns': float('inf'), 'epoch': 0}
    performance_records = {
        'success_rate': {},
        'ave_turns': {},
        'ave_reward': {},
        'bellman_loss': {},
        'eval_dialog_turns': {},
    }
    _sds = int(params['sample_dialog_seed'])
    if _sds < 0:
        sample_dialog_rng_seed = random.randint(0, 2**31 - 1)
        print('Sample dialogue: random RNG seed = %s (truyá»n --sample_dialog_seed %s Äá» tÃ¡i táº¡o)'
              % (sample_dialog_rng_seed, sample_dialog_rng_seed))
    else:
        sample_dialog_rng_seed = _sds
    sample_dialog_ab_state = {'before': None, 'seed': sample_dialog_rng_seed}

    def rollout_predict_transcript(dialog_manager, policy_agent, rng_seed):
        """
        Run one real-user-sim episode in predict mode with fixed RNG so the same
        user goal / stochastic user choices repeat across policy snapshots.
        """
        prev_agent = dialog_manager.agent
        try:
            numpy.random.seed(rng_seed)
            random.seed(rng_seed)
            torch.manual_seed(params['torch_seed'])
            dialog_manager.agent = policy_agent
            policy_agent.predict_mode = True
            dialog_manager.initialize_episode(True)
            goal = copy.deepcopy(dialog_manager.user.goal)
            episode_over = False
            reward = 0.0
            while not episode_over:
                episode_over, reward = dialog_manager.next_turn(
                    record_training_data=False,
                    record_training_data_for_user=False,
                )
            hist = dialog_manager.state_tracker.dialog_history_dictionaries()
            from plotting.compare_sample_dialog import (
                format_outcome_footer,
                format_turns_as_conversation,
            )
            nlg_model = policy_agent.nlg_model
            body = format_turns_as_conversation(goal, hist, nlg_model)
            footer = format_outcome_footer(
                reward,
                dialog_manager.state_tracker.turn_count,
                reward > 0,
            )
            return {
                'conversation': body + '\n\n' + footer,
                'goal': goal,
                'turns': copy.deepcopy(hist),
                'outcome': {
                    'reward': reward,
                    'turn_count': int(dialog_manager.state_tracker.turn_count),
                    'success': bool(reward > 0),
                },
            }
        finally:
            dialog_manager.agent = prev_agent

    def save_model(path, agt, success_rate, agent, best_epoch, cur_epoch):
        filename = f'agt_{agt}_{best_epoch}_{cur_epoch}_{success_rate:.5f}.pkl'
        filepath = os.path.join(path, filename)
        try:
            agent.save(filepath)
            print(f'saved model in {filepath}')
        except Exception as e:
            print(f'Error writing model {filepath}: {e}')

    def save_performance_records(path, agt, records):
        filepath = os.path.join(path, f'agt_{agt}_performance_records.json')
        try:
            with open(filepath, 'w', encoding='utf-8') as f:
                json.dump(records, f, ensure_ascii=False, indent=2)
            print(f'saved records in {filepath}')
        except Exception as e:
            print(f'Error writing records {filepath}: {e}')

    def simulation_epoch(n):
        successes = 0
        cumulative_reward = 0
        cumulative_turns = 0
        dialog_turns = []
        for _ in range(n):
            dialog_manager.initialize_episode(use_environment=True)
            episode_over = False
            while not episode_over:
                episode_over, reward = dialog_manager.next_turn(record_training_data_for_user=False)
                cumulative_reward += reward
                if episode_over:
                    if reward > 0:
                        successes += 1
                    tc = int(dialog_manager.state_tracker.turn_count)
                    cumulative_turns += tc
                    dialog_turns.append(tc)
        return {
            'success_rate': successes / n,
            'ave_reward': cumulative_reward / n,
            'ave_turns': cumulative_turns / n,
            'dialog_turns': dialog_turns,
        }

    def metrics_summary(sim_res):
        return {
            'success_rate': sim_res['success_rate'],
            'ave_turns': sim_res['ave_turns'],
            'ave_reward': sim_res['ave_reward'],
        }

    def evaluate_policy(policy_agent, n_episodes):
        """Evaluate policy in predict mode without recording training data."""
        prev_agent = dialog_manager.agent
        prev_predict = policy_agent.predict_mode
        try:
            dialog_manager.agent = policy_agent
            policy_agent.predict_mode = True
            return simulation_epoch(n_episodes)
        finally:
            policy_agent.predict_mode = prev_predict
            dialog_manager.agent = prev_agent

    def simulation_epoch_for_training(n, grounded_for_model=False):
        for episode in range(n):
            use_environment = (episode % n == 0) or grounded_for_model
            dialog_manager.initialize_episode(use_environment)
            episode_over = False
            while not episode_over:
                episode_over, reward = dialog_manager.next_turn()

    def warm_start_simulation(tb_writer=None):
        successes = 0
        cumulative_reward = 0
        cumulative_turns = 0
        for episode in range(warm_start_epochs):
            dialog_manager.initialize_episode(use_environment=True)
            episode_over = False
            while not episode_over:
                episode_over, reward = dialog_manager.next_turn()
                cumulative_reward += reward
                if episode_over:
                    if reward > 0:
                        successes += 1
                    cumulative_turns += dialog_manager.state_tracker.turn_count
        if params['boosted']:
            world_model.train(batch_size, num_batches=5)
        else:
            world_model.training_examples = []
        agent.warm_start = 2
        print(f"Warm_Start {warm_start_epochs} epochs, success rate "
              f"{successes / warm_start_epochs}, ave reward "
              f"{cumulative_reward / warm_start_epochs}, ave turns "
              f"{cumulative_turns / warm_start_epochs}")
        print(f"Current experience replay buffer size {len(agent.experience_replay_pool)}")
        if tb_writer is not None:
            n = float(warm_start_epochs)
            tb_writer.add_scalar('warm_start/success_rate', successes / n, 0)
            tb_writer.add_scalar('warm_start/ave_reward', cumulative_reward / n, 0)
            tb_writer.add_scalar('warm_start/ave_turns', cumulative_turns / n, 0)
            tb_writer.add_scalar('warm_start/replay_buffer_size', len(agent.experience_replay_pool), 0)
            tb_writer.flush()

    def run_episodes(count, status):
        successes = 0
        cumulative_reward = 0
        cumulative_turns = 0
        grounded_for_model = params['grounded']
        sim_eps = planning_steps + 1
        n_eval_train = params['simulation_epoch_size']
        n_eval_ab = params['eval_baseline_episodes']
        metrics_ab_state = {}

        tb_writer = None
        if params.get('tensorboard') and agt == 9 and params['trained_model_path'] is None:
            if SummaryWriter is None:
                print('TensorBoard disabled: install package with  pip install tensorboard')
            else:
                tb_root = (params.get('tensorboard_dir') or '').strip()
                if not tb_root:
                    tb_root = os.path.join(params['write_model_dir'], 'tensorboard')
                run_name = datetime.now().strftime('run_%Y%m%d_%H%M%S')
                log_dir = os.path.join(tb_root, run_name)
                os.makedirs(log_dir, exist_ok=True)
                tb_writer = SummaryWriter(log_dir=log_dir)
                print(f'TensorBoard log dir: {log_dir}')
                print(f'Start viewer: tensorboard --logdir "{tb_root}"')

        if agt == 9 and params['trained_model_path'] is None and warm_start == 1:
            print('warm_start starting ...')
            warm_start_simulation(tb_writer)
            print('warm_start finished, start RL training ...')

        if agt == 9 and params['trained_model_path'] is None:
            print('Baseline metrics (before RL, %d dialogs) ...' % n_eval_ab)
            before_sim = evaluate_policy(copy.deepcopy(agent), n_eval_ab)
            metrics_ab_state = {
                'eval_episodes': n_eval_ab,
                'before_rl': metrics_summary(before_sim),
            }
            print('Recording sample dialog (before RL) for before/after comparison ...')
            sample_dialog_ab_state['before'] = rollout_predict_transcript(
                dialog_manager, copy.deepcopy(agent), sample_dialog_ab_state['seed'],
            )

        for episode in range(count):
            print(f"Episode: {episode}")
            agent.predict_mode = False
            dialog_manager.initialize_episode(True)
            episode_over = False
            while not episode_over:
                episode_over, reward = dialog_manager.next_turn(record_training_data_for_user=False)
                cumulative_reward += reward
                if episode_over:
                    print("Successful Dialog!" if reward > 0 else "Failed Dialog!")
                    if reward > 0:
                        successes += 1
                    cumulative_turns += dialog_manager.state_tracker.turn_count

            if agt == 9 and params['trained_model_path'] is None:
                agent.predict_mode = True
                world_model.predict_mode = True
                simulation_epoch_for_training(sim_eps, grounded_for_model)

                agent.predict_mode = False
                world_model.predict_mode = False
                sim_res = simulation_epoch(n_eval_train)

                performance_records['success_rate'][episode] = sim_res['success_rate']
                performance_records['ave_turns'][episode] = sim_res['ave_turns']
                performance_records['ave_reward'][episode] = sim_res['ave_reward']
                performance_records['eval_dialog_turns'][episode] = sim_res['dialog_turns']

                if sim_res['success_rate'] >= best_res['success_rate']:
                    if sim_res['success_rate'] >= success_rate_threshold:
                        agent.predict_mode = True
                        world_model.predict_mode = True
                        simulation_epoch_for_training(sim_eps, grounded_for_model)

                if sim_res['success_rate'] > best_res['success_rate']:
                    best_model['model'] = copy.deepcopy(agent)
                    best_res.update(sim_res)
                    best_res['epoch'] = episode

                agent.train(batch_size, 1)
                performance_records['bellman_loss'][episode] = getattr(
                    agent, 'last_avg_bellman_loss', 0.0
                )

                # Train world model continuously â no freeze; the model improves
                # alongside the policy and avoids the abrupt distribution shift
                # that a mid-training buffer clear causes.
                if params['train_world_model']:
                    world_model.train(batch_size, 1)

                if tb_writer is not None:
                    step = episode
                    tb_writer.add_scalar('simulation/success_rate', sim_res['success_rate'], step)
                    tb_writer.add_scalar('simulation/ave_turns', sim_res['ave_turns'], step)
                    tb_writer.add_scalar('simulation/ave_reward', sim_res['ave_reward'], step)
                    tb_writer.add_scalar('dqn/bellman_loss', performance_records['bellman_loss'][episode], step)
                    tb_writer.add_scalar('rollout/running_success_rate', successes / (episode + 1), step)
                    tb_writer.add_scalar('rollout/running_avg_reward', cumulative_reward / (episode + 1), step)
                    tb_writer.add_scalar('rollout/running_avg_turns', cumulative_turns / (episode + 1), step)
                    tb_writer.add_scalar('buffer/replay_real_env', len(agent.experience_replay_pool), step)
                    tb_writer.add_scalar('buffer/replay_world_model', len(agent.experience_replay_pool_from_model), step)
                    if params['train_world_model']:
                        te = len(world_model.training_examples)
                        denom = max(1.0, float(te) / float(batch_size))
                        wm_avg = float(world_model.total_loss) / denom if te > 0 else 0.0
                        tb_writer.add_scalar('world_model/train_loss', wm_avg, step)
                    tb_writer.flush()

                if episode % save_check_point == 0:
                    save_model(params['write_model_dir'], agt, best_res['success_rate'],
                               best_model['model'], best_res['epoch'], episode)
                    save_performance_records(params['write_model_dir'], agt, performance_records)

            print(f"Progress: {episode + 1} / {count}, Success rate: {successes} / {episode + 1} "
                  f"Avg reward: {cumulative_reward / (episode + 1):.2f} "
                  f"Avg turns: {cumulative_turns / (episode + 1):.2f}")

        print(f"Success rate: {successes} / {count} "
              f"Avg reward: {cumulative_reward / count:.2f} "
              f"Avg turns: {cumulative_turns / count:.2f}")
        status['successes'] += successes
        status['count'] += count

        if agt == 9 and params['trained_model_path'] is None:
            if metrics_ab_state.get('before_rl') is not None:
                try:
                    print('Metrics after RL (best policy, %d dialogs) ...' % n_eval_ab)
                    after_sim = evaluate_policy(best_model['model'], n_eval_ab)
                    before_m = metrics_ab_state['before_rl']
                    after_m = metrics_summary(after_sim)
                    performance_records['metrics_ab'] = {
                        'eval_episodes': metrics_ab_state['eval_episodes'],
                        'before_rl': before_m,
                        'after_best_policy': {
                            **after_m,
                            'best_rl_epoch': int(best_res['epoch']),
                        },
                        'delta': {
                            'success_rate': after_m['success_rate'] - before_m['success_rate'],
                            'ave_turns': after_m['ave_turns'] - before_m['ave_turns'],
                            'ave_reward': after_m['ave_reward'] - before_m['ave_reward'],
                        },
                    }
                    print('=== Metrics before / after RL ===')
                    for key, label in (
                        ('success_rate', 'Success rate'),
                        ('ave_turns', 'Avg turns'),
                        ('ave_reward', 'Avg reward'),
                    ):
                        b, a = before_m[key], after_m[key]
                        print('  %s: %.4f -> %.4f (delta %+.4f)' % (label, b, a, a - b))
                    print('Saved metrics_ab to performance_records.')
                except Exception as e:
                    print('Could not save metrics_ab: %s' % e)
            if sample_dialog_ab_state['before'] is not None:
                try:
                    before_rec = sample_dialog_ab_state['before']
                    after_rec = rollout_predict_transcript(
                        dialog_manager,
                        best_model['model'],
                        sample_dialog_ab_state['seed'],
                    )
                    performance_records['sample_dialog_ab'] = {
                        'rng_seed': sample_dialog_ab_state['seed'],
                        'goal': before_rec['goal'],
                        'before_rl_conversation': before_rec['conversation'],
                        'after_best_conversation': after_rec['conversation'],
                        'before_turns': before_rec['turns'],
                        'after_turns': after_rec['turns'],
                        'before_outcome': before_rec['outcome'],
                        'after_outcome': after_rec['outcome'],
                        'best_rl_epoch': int(best_res['epoch']),
                    }
                    print('Saved sample_dialog_ab to performance_records.')
                except Exception as e:
                    print('Could not save sample_dialog_ab: %s' % e)
            save_model(params['write_model_dir'], agt, successes / count,
                       best_model['model'], best_res['epoch'], count)
            save_performance_records(params['write_model_dir'], agt, performance_records)

        if tb_writer is not None:
            tb_writer.close()

    run_episodes(num_episodes, status)


if __name__ == '__main__':
    main()
